import json
import base64
import hmac
import hashlib
import secrets

# Secret key for HMAC validation
secret_key = secrets.token_bytes(32)

def validate_session_cookie(session_cookie):
    try:
        # Verify HMAC signature
        signature = session_cookie[-32:]
        session_cookie_data = session_cookie[:-32]
        expected_signature = hmac.new(secret_key, session_cookie_data, hashlib.sha256).digest()
        if not hmac.compare_digest(signature, expected_signature):
            return False
        return True
    except Exception as e:
        return False

def load_user_session(request_payload):
    try:
        data = json.loads(request_payload)
        session_cookie = data.get("session_data")

        # Verify HMAC signature
        if not validate_session_cookie(session_cookie):
            return {"status": "error", "message": "Invalid session cookie"}

        # Validate session cookie length
        if len(session_cookie) > 1024:
            return {"status": "error", "message": "Session cookie too large"}

        # Attempt base64->JSON path
        try:
            decoded_data = base64.b64decode(session_cookie[:-32])
            user_obj = json.loads(decoded_data)
            return {
                "status": "success",
                "data": user_obj.get("username", "Unknown")
            }
        except Exception as inner_e:
            return {"status": "error", "message": str(inner_e)}

    except Exception as e:
        return {"status": "error", "message": str(e)}

def generate_session_cookie(username):
    try:
        user_obj = {"username": username}
        user_data = json.dumps(user_obj).encode('utf-8')
        signature = hmac.new(secret_key, user_data, hashlib.sha256).digest()
        session_cookie = base64.b64encode(user_data + signature)
        return session_cookie.decode('utf-8')
    except Exception as e:
        return None
